from cryptography.fernet import Fernet
import os

# Get the encryption key from the application config
key = os.environ['ENCRYPTION_KEY']

# Create a Fernet cipher object
cipher = Fernet(key.encode())

def encrypt_credit_card(credit_card_number):
    # Encrypt the credit card number
    encrypted_number = cipher.encrypt(credit_card_number.encode())
    return encrypted_number.decode()

def decrypt_credit_card(encrypted_number):
    # Decrypt the credit card number
    decrypted_number = cipher.decrypt(encrypted_number.encode()).decode()
    return decrypted_number